css:
body { font-family: 'Manrope', system-ui, sans-serif; margin: 0; background: hsl(20 23% 97%); display: flex; justify-content: center; align-items: center; min-height: 100vh; }



    /* ══════════════════════════════════════
       BLOCK: theme-name
       Scoped under .block-theme-name
       ══════════════════════════════════════ */

    .block-theme-name {
      display: flex;
      justify-content: center;
      width: 100%;
    }

    .block-theme-name__heading {
      max-width: 680px;
      color: hsl(var(--text-primary));
      text-align: center;
      font-family: var(--font-family-headings);
      font-size: var(--h1-font-size);
      font-style: normal;
      font-weight: var(--h1-font-weight);
      line-height: var(--h1-line-height);
      letter-spacing: var(--h1-letter-spacing);
      margin: 0;
    }

js:
const block = document.querySelector('.block-theme-name');
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); } });
    }, { threshold: 0.15 });
    block.querySelectorAll('.reveal').forEach(el => io.observe(el));
